  ('heelevel3-0c700c30-moex-00182', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-110-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '在某產品的生產過程中，廠長發現每多用一位員工，增產的幅度皆較前一位聘僱員工帶來的增產 幅度大，因此在此生產階段廠商的：', '["邊際成本遞增", "邊際成本遞減", "邊際成本固定", "無法判斷邊際成本遞增或遞減"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:06+00:00", "source_pdf_sha1": "b08f8b855b01", "answer_pdf_sha1": "82b5b8631449", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "327", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00183', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-110-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '假設電動汽車需求的價格彈性為2，供給的價格彈性為0.9，如果政府針對每部電動汽車的購買， 補貼消費者5萬元，相對於沒有補貼的情況，補貼後，下列敘述何者正確？', '["消費者剩餘增加的幅度超過生產者剩餘增加的幅度", "消費者剩餘增加的幅度小於生者者剩餘增加的幅度", "生產者剩餘不變", "社會福利不變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:06+00:00", "source_pdf_sha1": "b08f8b855b01", "answer_pdf_sha1": "82b5b8631449", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "327", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00184', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-110-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '在「李嘉圖恆等」理論下，若政府因為財政赤字而採用減稅措施，則對於本期的消費與儲蓄有什 麼影響？', '["消費增加、儲蓄減少", "消費增加、儲蓄增加", "消費不變、儲蓄不變", "消費減少、儲蓄增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:06+00:00", "source_pdf_sha1": "b08f8b855b01", "answer_pdf_sha1": "82b5b8631449", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "327", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00185', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-110-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '甲國的生產函數、儲蓄率、人口成長率、資本折舊率都與乙國相同。此外，假設兩國沒有技術進 步，且甲國每人平均資本量小於乙國。根據梭羅（Solow）模型，下列敘述何者正確？', '["甲國目前的每人平均產出大於乙國", "甲國目前的每人平均產出小於乙國", "長期時，甲國的每人平均產出大於乙國", "長期時，甲國的每人平均產出小於乙國"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:06+00:00", "source_pdf_sha1": "b08f8b855b01", "answer_pdf_sha1": "82b5b8631449", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "327", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00186', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-110-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '假定此經濟體中，民眾只能活兩期，而他第一期和第二期的所得分別為486元和264元。他在這 兩期皆要消費，且因為消費所得到的滿足為U=C 0.5C0.5，假定市場的利率為10%，則民眾第一期', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:06+00:00", "source_pdf_sha1": "b08f8b855b01", "answer_pdf_sha1": "82b5b8631449", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "327", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00187', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-110-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '2 的儲蓄為多少？', '["113元", "123元", "133元", "143元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:06+00:00", "source_pdf_sha1": "b08f8b855b01", "answer_pdf_sha1": "82b5b8631449", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "327", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
